1	/**
2	 * Individual channel strip for the mixer panel.
3	 * Fader, pan knob, mute/solo buttons, VU meter, track name.
4	 */
5	
6	import { useCallback } from "react";
7	import { Fader } from "@ui/controls/Fader";
8	import { RotaryKnob } from "@ui/controls/RotaryKnob";
9	import { VuMeter } from "@ui/controls/VuMeter";
10	import { volumeToDb } from "./format";
11	import styles from "./MixerPanel.module.css";
12	
13	type ChannelStripProps = {
14	  trackId: string;
15	  name: string;
16	  color: string;
17	  volume: number;
18	  pan: number;
19	  muted: boolean;
20	  solo: boolean;
21	  meterLevel: number;
22	  meterPeak: number;
23	  clipping: boolean;
24	  onVolumeChange: (trackId: string, volume: number) => void;
25	  onPanChange: (trackId: string, pan: number) => void;
26	  onMuteToggle: (trackId: string) => void;
27	  onSoloToggle: (trackId: string) => void;
28	};
29	
30	export function ChannelStrip({
31	  trackId,
32	  name,
33	  color,
34	  volume,
35	  pan,
36	  muted,
37	  solo,
38	  meterLevel,
39	  meterPeak,
40	  clipping,
41	  onVolumeChange,
42	  onPanChange,
43	  onMuteToggle,
44	  onSoloToggle,
45	}: ChannelStripProps): React.JSX.Element {
46	  const handleVolume = useCallback(
47	    (v: number) => {
48	      onVolumeChange(trackId, v / 100);
49	    },
50	    [trackId, onVolumeChange],
51	  );
52	  const handlePan = useCallback(
53	    (v: number) => {
54	      onPanChange(trackId, v / 100);
55	    },
56	    [trackId, onPanChange],
57	  );
58	  const handleMute = useCallback(() => {
59	    onMuteToggle(trackId);
60	  }, [trackId, onMuteToggle]);
61	  const handleSolo = useCallback(() => {
62	    onSoloToggle(trackId);
63	  }, [trackId, onSoloToggle]);
64	
65	  const stripClass = [styles["strip"], muted ? styles["strip-muted"] : ""]
66	    .filter(Boolean)
67	    .join(" ");
68	
69	  return (
70	    <div className={stripClass} data-testid={`channel-strip-${trackId}`}>
71	      <div
72	        style={{
73	          width: "100%",
74	          height: 3,
75	          backgroundColor: color,
76	        }}
77	      />
78	      <div className={styles["name"]}>{name}</div>
79	
80	      <RotaryKnob
81	        value={Math.round(pan * 100)}
82	        min={-100}
83	        max={100}
84	        step={1}
85	        onChange={handlePan}
86	        label="PAN"
87	        size={32}
88	      />
89	
90	      <div className={styles["meter-fader-row"]}>
91	        <VuMeter
92	          level={meterLevel}
93	          peak={meterPeak}
94	          clip={clipping}
95	          width={8}
96	          height={96}
97	        />
98	        <Fader
99	          value={Math.round(volume * 100)}
100	          min={0}
101	          max={200}
102	          step={1}
103	          onChange={handleVolume}
104	          label=""
105	          height={96}
106	        />
107	      </div>
108	
109	      <div className={styles["db-label"]}>{volumeToDb(volume)}</div>
110	
111	      <div className={styles["controls-row"]}>
112	        <button
113	          className={
114	            muted ? (styles["btn-mute-active"] ?? "") : (styles["btn"] ?? "")
115	          }
116	          onClick={handleMute}
117	          aria-label={muted ? "Unmute" : "Mute"}
118	          aria-pressed={muted}
119	          type="button"
120	        >
121	          M
122	        </button>
123	        <button
124	          className={
125	            solo ? (styles["btn-solo-active"] ?? "") : (styles["btn"] ?? "")
126	          }
127	          onClick={handleSolo}
128	          aria-label={solo ? "Unsolo" : "Solo"}
129	          aria-pressed={solo}
130	          type="button"
131	        >
132	          S
133	        </button>
134	      </div>
135	    </div>
136	  );
137	}
