1	/**
2	 * E13: Routing matrix UI.
3	 * Visual overview of all track outputs, sends, bus assignments, and sidechains.
4	 */
5	
6	import { useDawStore } from "@state/store";
7	import { useRoutingStore } from "@state/routing/routing-store";
8	import styles from "./RoutingMatrix.module.css";
9	
10	function SendCell({
11	  trackId,
12	  busId,
13	  level,
14	  preFader,
15	}: {
16	  trackId: string;
17	  busId: string;
18	  level: number;
19	  preFader: boolean;
20	}): React.JSX.Element {
21	  const updateSendLevel = useRoutingStore((s) => s.updateSendLevel);
22	  const togglePreFader = useRoutingStore((s) => s.togglePreFader);
23	
24	  return (
25	    <td
26	      className={styles["send-cell-active"]}
27	      data-testid={`send-cell-${trackId}-${busId}`}
28	    >
29	      <input
30	        type="range"
31	        min={0}
32	        max={100}
33	        value={Math.round(level * 100)}
34	        onChange={(e) => {
35	          updateSendLevel(trackId, busId, Number(e.target.value) / 100);
36	        }}
37	        className={styles["send-slider"]}
38	        aria-label={`Send level ${trackId} to ${busId}`}
39	      />
40	      <button
41	        className={preFader ? styles["pre-active"] : styles["pre"]}
42	        onClick={() => {
43	          togglePreFader(trackId, busId);
44	        }}
45	        type="button"
46	        aria-label={preFader ? "Switch to post-fader" : "Switch to pre-fader"}
47	      >
48	        {preFader ? "PRE" : "POST"}
49	      </button>
50	    </td>
51	  );
52	}
53	
54	function EmptyCell({
55	  trackId,
56	  busId,
57	}: {
58	  trackId: string;
59	  busId: string;
60	}): React.JSX.Element {
61	  const addSend = useRoutingStore((s) => s.addSend);
62	
63	  return (
64	    <td
65	      className={styles["send-cell"]}
66	      data-testid={`send-cell-${trackId}-${busId}`}
67	    >
68	      <button
69	        className={styles["add-send"]}
70	        onClick={() => {
71	          addSend(trackId, { busId, level: 0.5, preFader: false });
72	        }}
73	        type="button"
74	        aria-label={`Add send from ${trackId} to ${busId}`}
75	      >
76	        +
77	      </button>
78	    </td>
79	  );
80	}
81	
82	export function RoutingMatrix(): React.JSX.Element {
83	  const tracks = useDawStore((s) => s.tracks);
84	  const buses = useRoutingStore((s) => s.buses);
85	  const sends = useRoutingStore((s) => s.sends);
86	  const sidechains = useRoutingStore((s) => s.sidechains);
87	
88	  const busIds = Object.keys(buses);
89	
90	  return (
91	    <section data-testid="routing-matrix" className={styles["matrix"]}>
92	      {busIds.length === 0 ? (
93	        <div className={styles["empty"]}>No buses configured</div>
94	      ) : (
95	        <table className={styles["table"]}>
96	          <thead>
97	            <tr>
98	              <th className={styles["header"]}>Track</th>
99	              {busIds.map((busId) => {
100	                const bus = buses[busId];
101	                if (!bus) return null;
102	                return (
103	                  <th key={busId} className={styles["header"]}>
104	                    <div>{bus.name}</div>
105	                    <div className={styles["bus-target"]}>
106	                      -&gt; {bus.outputTarget}
107	                    </div>
108	                  </th>
109	                );
110	              })}
111	              <th className={styles["header"]}>SC</th>
112	            </tr>
113	          </thead>
114	          <tbody>
115	            {tracks.map((track) => {
116	              const trackSends = sends[track.id] ?? [];
117	              const trackSidechains = sidechains.filter(
118	                (sc) => sc.sourceId === track.id || sc.targetId === track.id,
119	              );
120	
121	              return (
122	                <tr key={track.id}>
123	                  <td className={styles["track-name"]}>{track.name}</td>
124	                  {busIds.map((busId) => {
125	                    const send = trackSends.find((s) => s.busId === busId);
126	                    if (send) {
127	                      return (
128	                        <SendCell
129	                          key={busId}
130	                          trackId={track.id}
131	                          busId={busId}
132	                          level={send.level}
133	                          preFader={send.preFader}
134	                        />
135	                      );
136	                    }
137	                    return (
138	                      <EmptyCell key={busId} trackId={track.id} busId={busId} />
139	                    );
140	                  })}
141	                  <td className={styles["sc-cell"]}>
142	                    {trackSidechains.map((sc) => (
143	                      <span
144	                        key={`${sc.sourceId}-${sc.targetId}`}
145	                        data-testid={`sidechain-${sc.sourceId}-${sc.targetId}`}
146	                        className={styles["sc-badge"]}
147	                      >
148	                        {sc.sourceId === track.id
149	                          ? `-> ${sc.targetId}`
150	                          : `<- ${sc.sourceId}`}
151	                      </span>
152	                    ))}
153	                  </td>
154	                </tr>
155	              );
156	            })}
157	          </tbody>
158	        </table>
159	      )}
160	    </section>
161	  );
162	}
