1	/**
2	 * State types for E13 routing.
3	 * Serializable representations of sends, buses, and sidechains.
4	 */
5	
6	export type SendState = {
7	  readonly busId: string;
8	  readonly level: number;
9	  readonly preFader: boolean;
10	};
11	
12	export type BusState = {
13	  readonly id: string;
14	  readonly name: string;
15	  readonly outputTarget: string; // "master" or bus id
16	};
17	
18	export type SidechainState = {
19	  readonly sourceId: string;
20	  readonly targetId: string;
21	};
