1	/**
2	 * Zustand store for E13 routing state.
3	 * Per-track sends, bus definitions, and sidechain assignments.
4	 */
5	
6	import { create } from "zustand";
7	import type { SendState, BusState, SidechainState } from "./types";
8	
9	export type RoutingStore = {
10	  buses: Record<string, BusState>;
11	  sends: Record<string, readonly SendState[]>;
12	  sidechains: readonly SidechainState[];
13	
14	  addBus: (bus: BusState) => void;
15	  removeBus: (id: string) => void;
16	  setBusOutput: (busId: string, targetId: string) => void;
17	
18	  addSend: (trackId: string, send: SendState) => void;
19	  removeSend: (trackId: string, busId: string) => void;
20	  updateSendLevel: (trackId: string, busId: string, level: number) => void;
21	  togglePreFader: (trackId: string, busId: string) => void;
22	  removeTrackSends: (trackId: string) => void;
23	  getSends: (trackId: string) => readonly SendState[];
24	
25	  addSidechain: (sc: SidechainState) => void;
26	  removeSidechain: (sourceId: string, targetId: string) => void;
27	  getSidechains: (targetId: string) => readonly SidechainState[];
28	};
29	
30	export const useRoutingStore = create<RoutingStore>()((set, get) => ({
31	  buses: {},
32	  sends: {},
33	  sidechains: [],
34	
35	  addBus(bus) {
36	    set((s) => ({
37	      buses: { ...s.buses, [bus.id]: bus },
38	    }));
39	  },
40	
41	  removeBus(id) {
42	    set((s) => {
43	      const buses = Object.fromEntries(
44	        Object.entries(s.buses)
45	          .filter(([k]) => k !== id)
46	          .map(([k, bus]) =>
47	            bus.outputTarget === id
48	              ? [k, { ...bus, outputTarget: "master" }]
49	              : [k, bus],
50	          ),
51	      );
52	      const sends = Object.fromEntries(
53	        Object.entries(s.sends)
54	          .filter(([trackId]) => trackId !== id) // Remove sends FROM this bus
55	          .map(
56	            ([trackId, trackSends]) =>
57	              [
58	                trackId,
59	                trackSends.filter((send) => send.busId !== id),
60	              ] as const,
61	          )
62	          .filter(([, filtered]) => filtered.length > 0),
63	      );
64	      const sidechains = s.sidechains.filter(
65	        (sc) => sc.sourceId !== id && sc.targetId !== id,
66	      );
67	      return { buses, sends, sidechains };
68	    });
69	  },
70	
71	  setBusOutput(busId, targetId) {
72	    set((s) => {
73	      const bus = s.buses[busId];
74	      if (!bus) return s;
75	      return {
76	        buses: { ...s.buses, [busId]: { ...bus, outputTarget: targetId } },
77	      };
78	    });
79	  },
80	
81	  addSend(trackId, send) {
82	    set((s) => {
83	      const existing = s.sends[trackId] ?? [];
84	      if (existing.some((e) => e.busId === send.busId)) return s;
85	      return {
86	        sends: { ...s.sends, [trackId]: [...existing, send] },
87	      };
88	    });
89	  },
90	
91	  removeSend(trackId, busId) {
92	    set((s) => {
93	      const existing = s.sends[trackId];
94	      if (!existing) return s;
95	      const next = existing.filter((send) => send.busId !== busId);
96	      if (next.length === 0) {
97	        return {
98	          sends: Object.fromEntries(
99	            Object.entries(s.sends).filter(([k]) => k !== trackId),
100	          ),
101	        };
102	      }
103	      return { sends: { ...s.sends, [trackId]: next } };
104	    });
105	  },
106	
107	  updateSendLevel(trackId, busId, level) {
108	    set((s) => {
109	      const existing = s.sends[trackId];
110	      if (!existing) return s;
111	      const clamped = Math.min(1, Math.max(0, level));
112	      return {
113	        sends: {
114	          ...s.sends,
115	          [trackId]: existing.map((send) =>
116	            send.busId === busId ? { ...send, level: clamped } : send,
117	          ),
118	        },
119	      };
120	    });
121	  },
122	
123	  togglePreFader(trackId, busId) {
124	    set((s) => {
125	      const existing = s.sends[trackId];
126	      if (!existing) return s;
127	      return {
128	        sends: {
129	          ...s.sends,
130	          [trackId]: existing.map((send) =>
131	            send.busId === busId ? { ...send, preFader: !send.preFader } : send,
132	          ),
133	        },
134	      };
135	    });
136	  },
137	
138	  removeTrackSends(trackId) {
139	    set((s) => ({
140	      sends: Object.fromEntries(
141	        Object.entries(s.sends).filter(([k]) => k !== trackId),
142	      ),
143	    }));
144	  },
145	
146	  getSends(trackId) {
147	    return get().sends[trackId] ?? [];
148	  },
149	
150	  addSidechain(sc) {
151	    set((s) => {
152	      const exists = s.sidechains.some(
153	        (existing) =>
154	          existing.sourceId === sc.sourceId &&
155	          existing.targetId === sc.targetId,
156	      );
157	      if (exists) return s;
158	      return { sidechains: [...s.sidechains, sc] };
159	    });
160	  },
161	
162	  removeSidechain(sourceId, targetId) {
163	    set((s) => ({
164	      sidechains: s.sidechains.filter(
165	        (sc) => !(sc.sourceId === sourceId && sc.targetId === targetId),
166	      ),
167	    }));
168	  },
169	
170	  getSidechains(targetId) {
171	    return get().sidechains.filter((sc) => sc.targetId === targetId);
172	  },
173	}));
