1	/**
2	 * Insert chain manager for mixer channel strips.
3	 * Manages a serial chain of effect nodes between source and destination.
4	 * Re-wires the Web Audio graph when inserts are added/removed.
5	 */
6	
7	export type InsertEntry = {
8	  readonly id: string;
9	  readonly input: AudioNode;
10	  readonly output: AudioNode;
11	};
12	
13	export type InsertChain = {
14	  addInsert(id: string, input: AudioNode, output: AudioNode): void;
15	  replaceInsert(id: string, input: AudioNode, output: AudioNode): void;
16	  removeInsert(id: string): void;
17	  getInserts(): readonly InsertEntry[];
18	  dispose(): void;
19	};
20	
21	/** Safe array access for the insert chain */
22	function at(entries: InsertEntry[], i: number): InsertEntry {
23	  const e = entries[i];
24	  if (!e) throw new Error("Insert index out of bounds");
25	  return e;
26	}
27	
28	export function createInsertChain(
29	  source: AudioNode,
30	  dest: AudioNode,
31	): InsertChain {
32	  const inserts: InsertEntry[] = [];
33	
34	  // Track the node source currently connects to, so we can disconnect
35	  // only our connection instead of severing all outgoing connections.
36	  let sourceTarget: AudioNode = dest;
37	
38	  function rewire(): void {
39	    // Disconnect only the chain's own connections
40	    try {
41	      source.disconnect(sourceTarget);
42	    } catch {
43	      // Target already disconnected — safe to ignore
44	    }
45	    for (const entry of inserts) {
46	      entry.output.disconnect();
47	    }
48	
49	    if (inserts.length === 0) {
50	      source.connect(dest);
51	      sourceTarget = dest;
52	      return;
53	    }
54	
55	    // source -> first insert input
56	    const first = at(inserts, 0);
57	    source.connect(first.input);
58	    sourceTarget = first.input;
59	
60	    // Chain inserts: each output -> next input
61	    for (let i = 0; i < inserts.length - 1; i++) {
62	      const current = at(inserts, i);
63	      const next = at(inserts, i + 1);
64	      current.output.connect(next.input);
65	    }
66	
67	    // Last insert output -> dest
68	    const last = at(inserts, inserts.length - 1);
69	    last.output.connect(dest);
70	  }
71	
72	  // Initial wiring: source -> dest
73	  source.connect(dest);
74	
75	  return {
76	    addInsert(id: string, input: AudioNode, output: AudioNode): void {
77	      inserts.push({ id, input, output });
78	      rewire();
79	    },
80	
81	    replaceInsert(id: string, input: AudioNode, output: AudioNode): void {
82	      const idx = inserts.findIndex((e) => e.id === id);
83	      if (idx === -1) {
84	        throw new Error(`replaceInsert: insert "${id}" not found in chain`);
85	      }
86	      const old = at(inserts, idx);
87	      old.input.disconnect();
88	      old.output.disconnect();
89	      inserts[idx] = { id, input, output };
90	      rewire();
91	    },
92	
93	    removeInsert(id: string): void {
94	      const idx = inserts.findIndex((e) => e.id === id);
95	      if (idx === -1) return;
96	      const removed = at(inserts, idx);
97	      removed.output.disconnect();
98	      inserts.splice(idx, 1);
99	      rewire();
100	    },
101	
102	    getInserts(): readonly InsertEntry[] {
103	      return [...inserts];
104	    },
105	
106	    dispose(): void {
107	      try {
108	        source.disconnect(sourceTarget);
109	      } catch {
110	        // Already disconnected
111	      }
112	      for (const entry of inserts) {
113	        entry.output.disconnect();
114	      }
115	      inserts.length = 0;
116	    },
117	  };
118	}
