62	/** Kahn's algorithm topological sort */
63	function topologicalSort(graph: RoutingGraph): readonly string[] {
64	  const nodes = graph.getNodes();
65	  if (nodes.length === 0) return [];
66	
67	  const inDegree = new Map<string, number>();
68	  for (const n of nodes) inDegree.set(n, 0);
69	
70	  for (const n of nodes) {
71	    for (const neighbor of graph.getEdges(n)) {
72	      inDegree.set(neighbor, (inDegree.get(neighbor) ?? 0) + 1);
73	    }
74	  }
75	
76	  const queue: string[] = [];
77	  for (const [n, deg] of inDegree) {
78	    if (deg === 0) queue.push(n);
79	  }
80	
81	  const result: string[] = [];
82	  while (queue.length > 0) {
83	    const current = queue.shift();
84	    if (current === undefined) break;
85	    result.push(current);
86	    for (const neighbor of graph.getEdges(current)) {
87	      const newDeg = (inDegree.get(neighbor) ?? 1) - 1;
88	      inDegree.set(neighbor, newDeg);
89	      if (newDeg === 0) queue.push(neighbor);
90	    }
91	  }
92	
93	  return result;
94	}
