1	/**
2	 * Effects rack for a single track.
3	 * Shows insert chain with add/remove/bypass controls.
4	 */
5	
6	import { useState, useCallback } from "react";
7	import { useEffectsStore } from "@state/effects";
8	import { useEffectsBridgeContext } from "@audio/effects/EffectsBridgeProvider";
9	import { tokens } from "@ui/tokens/tokens";
10	import { useReducedMotion } from "@ui/hooks/useReducedMotion";
11	import { EffectPanel } from "./EffectPanel";
12	import { UndoToast, type UndoToastState } from "@ui/primitives/UndoToast";
13	import type { EffectSlotState } from "@state/effects/types";
14	
15	const EMPTY_SLOTS: readonly never[] = [];
16	
17	// Reverb A/B: swap between convolution and algorithmic reverb
18	const REVERB_SWAP: Record<string, string> = {
19	  reverb: "freeverb",
20	  freeverb: "reverb",
21	};
22	
23	type EffectsRackProps = {
24	  trackId: string;
25	};
26	
27	export function EffectsRack({ trackId }: EffectsRackProps): React.JSX.Element {
28	  const { registry } = useEffectsBridgeContext();
29	  const availableEffects = registry.getAll();
30	
31	  const slots = useEffectsStore((s) => s.trackEffects[trackId] ?? EMPTY_SLOTS);
32	  const addEffect = useEffectsStore((s) => s.addEffect);
33	  const removeEffect = useEffectsStore((s) => s.removeEffect);
34	  const updateEffectParam = useEffectsStore((s) => s.updateEffectParam);
35	  const toggleBypass = useEffectsStore((s) => s.toggleBypass);
36	  const swapEffectType = useEffectsStore((s) => s.swapEffectType);
37	
38	  const reducedMotion = useReducedMotion();
39	  const [showSelector, setShowSelector] = useState(false);
40	  const [undoPending, setUndoPending] = useState<UndoToastState | null>(null);
41	
42	  const handleRemove = useCallback(
43	    (slot: EffectSlotState) => {
44	      const snapshot = { ...slot, params: { ...slot.params } };
45	      const factory = registry.get(slot.typeId);
46	      const name = factory?.definition.name ?? slot.typeId;
47	      removeEffect(trackId, slot.id);
48	      setUndoPending({
49	        message: `Removed ${name}.`,
50	        onUndo: () => {
51	          addEffect(trackId, snapshot);
52	          setUndoPending(null);
53	        },
54	      });
55	    },
56	    [trackId, removeEffect, addEffect, registry],
57	  );
58	
59	  const handleUndoExpired = useCallback(() => {
60	    setUndoPending(null);
61	  }, []);
62	
63	  const handleSwapReverb = useCallback(
64	    (
65	      slotId: string,
66	      currentTypeId: string,
67	      currentParams: Record<string, number>,
68	    ) => {
69	      const targetTypeId = REVERB_SWAP[currentTypeId];
70	      if (targetTypeId === undefined || targetTypeId === "") return;
71	      const targetFactory = registry.get(targetTypeId);
72	      if (!targetFactory) return;
73	      const newParams: Record<string, number> = {};
74	      for (const p of targetFactory.definition.parameters) {
75	        newParams[p.key] = p.default;
76	      }
77	      // Preserve mix level for meaningful A/B comparison
78	      const currentMix = currentParams.mix;
79	      if (currentMix !== undefined) {
80	        newParams.mix = currentMix;
81	      }
82	      swapEffectType(trackId, slotId, targetTypeId, newParams);
83	    },
84	    [trackId, swapEffectType, registry],
85	  );
86	
87	  const handleAdd = useCallback(
88	    (typeId: string) => {
89	      const factory = registry.get(typeId);
90	      if (!factory) return;
91	
92	      const id = `${typeId}-${crypto.randomUUID().slice(0, 8)}`;
93	      const params: Record<string, number> = {};
94	      for (const p of factory.definition.parameters) {
95	        params[p.key] = p.default;
96	      }
97	
98	      addEffect(trackId, { id, typeId, bypassed: false, params });
99	      setShowSelector(false);
100	    },
101	    [trackId, addEffect, registry],
102	  );
103	
104	  return (
105	    <div
106	      data-testid="effects-rack"
107	      style={{
108	        display: "flex",
109	        flexDirection: "column",
110	        gap: tokens.space[1],
111	        padding: tokens.space[2],
112	        borderTop: "2px solid var(--color-gray-700)",
113	        backgroundColor: tokens.color.gray900,
114	        minHeight: 40,
115	      }}
116	    >
117	      {!reducedMotion && (
118	        <style>{`
119	          @keyframes selectorSlideIn {
120	            from { opacity: 0; transform: translateY(-4px); }
121	            to { opacity: 1; transform: translateY(0); }
122	          }
123	        `}</style>
124	      )}
125	      {slots.map((slot) => {
126	        const factory = registry.get(slot.typeId);
127	        if (!factory) return null;
128	
129	        const isReverbType = slot.typeId in REVERB_SWAP;
130	        const swapTarget = REVERB_SWAP[slot.typeId];
131	        const swapTargetFactory =
132	          swapTarget !== undefined && swapTarget !== ""
133	            ? registry.get(swapTarget)
134	            : undefined;
135	
136	        return (
137	          <EffectPanel
138	            key={slot.id}
139	            definition={factory.definition}
140	            params={slot.params}
141	            bypassed={slot.bypassed}
142	            onParamChange={(key, value) => {
143	              updateEffectParam(trackId, slot.id, key, value);
144	            }}
145	            onBypassToggle={() => {
146	              toggleBypass(trackId, slot.id);
147	            }}
148	            onRemove={() => {
149	              handleRemove(slot);
150	            }}
151	            onSwapType={
152	              isReverbType
153	                ? () => {
154	                    handleSwapReverb(slot.id, slot.typeId, slot.params);
155	                  }
156	                : undefined
157	            }
158	            swapLabel={swapTargetFactory?.definition.name}
159	          />
160	        );
161	      })}
162	
163	      {showSelector ? (
164	        <div
165	          style={{
166	            display: "flex",
167	            flexWrap: "wrap",
168	            gap: tokens.space[1],
169	            animation: reducedMotion
170	              ? undefined
171	              : "selectorSlideIn 150ms ease-out",
172	          }}
173	        >
174	          {availableEffects.map((f) => (
175	            <button
176	              key={f.definition.id}
177	              type="button"
178	              aria-label={`Add ${f.definition.name} effect`}
179	              onClick={() => {
180	                handleAdd(f.definition.id);
181	              }}
182	              style={{
183	                fontFamily: tokens.font.mono,
184	                fontSize: tokens.text.xs,
185	                border: "2px solid var(--color-gray-700)",
186	                background: "transparent",
187	                color: tokens.color.white,
188	                cursor: "pointer",
189	                padding: `${String(tokens.space[1])}px ${String(tokens.space[2])}px`,
190	              }}
