    const hasSolo = [...strips.values()].some((s) => s.solo);

    if (strip.muted) {
      strip.muteGain.gain.value = 0;
      return;
    }

    if (hasSolo) {
      if (strip.solo || strip.soloIsolate) {
        strip.muteGain.gain.value = 1;
      } else {
        strip.muteGain.gain.value = 0;
      }
    } else {
      strip.muteGain.gain.value = 1;
    }
